const { execSync } = require('child_process');

// Scan Local-Network-Hub for files modified in last 48h
const findCmd = `find /mnt/docs/Local-Network-Hub -name "*.md" -newer /mnt/docs/Local-Network-Hub/03-Inbox -type f 2>/dev/null | head -30`;
let recentFiles = '';
try {
    recentFiles = execSync(findCmd, { encoding: 'utf8' }).trim();
} catch(e) {
    recentFiles = '';
}

// Read Claude_Vault open tasks
let tasks = '';
try {
    const taskFind = `find /mnt/docs/Claude_Vault/tasks -name "*.md" -type f 2>/dev/null`;
    const taskFiles = execSync(taskFind, { encoding: 'utf8' }).trim().split('\n').filter(Boolean);
    const fs = require('fs');
    const snippets = taskFiles.slice(0, 10).map(f => {
        try {
            const c = fs.readFileSync(f, 'utf8');
            const titleLine = c.split('\n').find(l => l.startsWith('title:') || l.startsWith('# ')) || f;
            const statusLine = c.split('\n').find(l => l.startsWith('status:')) || '';
            return `- ${titleLine.replace(/^(title:|#)\s*/,'')} ${statusLine}`.trim();
        } catch { return ''; }
    }).filter(Boolean);
    tasks = snippets.join('\n');
} catch(e) {
    tasks = 'Could not read tasks.';
}

// Read content of recent files (first 300 chars each)
let context = '';
if (recentFiles) {
    const fs = require('fs');
    const files = recentFiles.split('\n').filter(Boolean);
    context = files.map(f => {
        try {
            const c = fs.readFileSync(f, 'utf8').substring(0, 300);
            return `### ${f.split('/').pop()}\n${c}`;
        } catch { return ''; }
    }).filter(Boolean).join('\n\n');
}

return [{ json: {
    tasks,
    context: context || 'No recent vault changes.',
    date: new Date().toISOString().substring(0, 10)
} }];

const d = $input.first().json;
const prompt = `Today is ${d.date}. You are a concise executive assistant.

OPEN TASKS:
${d.tasks || 'None found.'}

RECENT VAULT ACTIVITY:
${d.context}

Write a tight daily briefing (under 200 words):
1. Top 3 priority tasks for today with a one-line reason each
2. Any urgent items or deadlines visible in the notes
3. One suggested focus area

Be direct. No filler. Use markdown.`;

return [{ json: { prompt } }];

const resp = $input.first().json;
const briefing = resp.choices[0].message.content;

const now = new Date();
const pad = n => String(n).padStart(2,'0');
const ts  = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;

const content = `---
type: briefing
date: "${ts}"
generated: "${now.toISOString()}"
---

${briefing}
`;

const fs = require('fs');
const outPath = `/mnt/docs/Local-Network-Hub/00-System/daily-briefing-${ts}.md`;
fs.writeFileSync(outPath, content, 'utf8');

// Also overwrite a fixed "today" file for easy dashboard access
fs.writeFileSync('/mnt/docs/Local-Network-Hub/00-System/today.md', content, 'utf8');

return [{ json: { ok: true, file: outPath, preview: briefing.substring(0, 200) } }];
